import { useNavigate } from "react-router-dom";
import { useState, useEffect } from "react";
import booksData from "../data/booksData";
import "./styles/LibrarianBooks.css";

function LibrarianBooks() {
  const navigate = useNavigate();
  const genre = localStorage.getItem("genre");

  if (!genre || !booksData[genre]) {
    return <h2 style={{ padding: "40px" }}>Genre not found</h2>;
  }

  const statusKey = `status_${genre}`;

  const [statusMap, setStatusMap] = useState({});

  // 🔥 LOAD STATUS ON PAGE LOAD
  useEffect(() => {
    const saved =
      JSON.parse(localStorage.getItem(statusKey)) || {};
    setStatusMap(saved);
  }, [statusKey]);

  const toggleStatus = (title) => {
    const updated = {
      ...statusMap,
      [title]:
        statusMap[title] === "Not Available"
          ? "Available"
          : "Not Available",
    };

    setStatusMap(updated);
    localStorage.setItem(statusKey, JSON.stringify(updated));
  };

  const books = booksData[genre];

  return (
    <div className="books-page">
      <h1 className="books-title">Manage {genre} Books</h1>

      <div className="books-grid">
        {books.map((book, i) => {
          const currentStatus =
            statusMap[book.title] || "Available";

          return (
            <div key={i} className="book-card">
              <img src={book.cover} alt={book.title} />
              <h3>{book.title}</h3>
              <p>{book.author}</p>

              <span
                className={`card-status ${
                  currentStatus === "Available"
                    ? "avail"
                    : "not-avail"
                }`}
              >
                {currentStatus}
              </span>

              <button
                className="borrow-btn"
                onClick={() => toggleStatus(book.title)}
                style={{ marginTop: "12px" }}
              >
                Toggle Availability
              </button>
            </div>
          );
        })}
      </div>

      <div className="action-buttons">
        <button className="back-btn" onClick={() => navigate(-1)}>
          ← Back
        </button>
      </div>
    </div>
  );
}

export default LibrarianBooks;
